const items = $input.all();
const rows = items.map(i => {
  const p = i.json;
  const body = p.__response || {};
  const out = (body.output || body.text || JSON.stringify(body) || '');
  const failed = !out || /I hit an error|Connection error|Error in sub-node/i.test(out);
  return { agent: p.name, ok: !failed, sample: String(out).slice(0, 140) };
});
const pass = rows.filter(r => r.ok).length;
const md = `# CP Agent self-QA\n\n**${pass}/${rows.length} passed**\n\n` +
  rows.map(r => `- ${r.ok ? '✅' : '❌'} **${r.agent}** — ${r.sample}`).join('\n');
return [{ json: { passed: pass, total: rows.length, report_markdown: md, rows } }];
